const payload = $json.body || {};
const action = String(payload.action || payload.endpoint || '').trim().toLowerCase();

const env = {
  owner: $env.GITHUB_OWNER || '',
  repo: $env.GITHUB_REPO || '',
  token: $env.GITHUB_TOKEN || '',
  apiBase: ($env.GITHUB_API_BASE || 'https://api.github.com').replace(/\/$/, ''),
  defaultBaseBranch: $env.AGENT_BASE_BRANCH || 'main',
  defaultHeadBranch: $env.AGENT_HEAD_BRANCH || ''
};

function requireGithubConfig() {
  if (!env.owner || !env.repo) {
    throw new Error('GITHUB_OWNER and GITHUB_REPO are required.');
  }
  if (!env.token) {
    throw new Error('GITHUB_TOKEN is required.');
  }
}

function makeId(prefix) {
  return `${prefix}_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
}

function assessRisk(files, totalAdded, totalDeleted) {
  let score = 0;
  const total = totalAdded + totalDeleted;
  if (total > 350) score += 2;
  else if (total > 120) score += 1;

  const criticalMarkers = ['auth', 'payment', 'security', 'gateway', 'api', 'config'];
  if (files.some((path) => criticalMarkers.some((marker) => path.toLowerCase().includes(marker)))) score += 2;

  if (files.length > 10) score += 1;

  if (score >= 4) return 'high';
  if (score >= 2) return 'medium';
  return 'low';
}

function classifyChange(files, evidenceSnippets) {
  const lowerFiles = files.join(' ').toLowerCase();
  const lowerDiff = evidenceSnippets.join(' ').toLowerCase();
  if (/fix|bug|error/.test(lowerDiff)) return 'bugfix';
  if (/refactor/.test(lowerDiff)) return 'refactor';
  if (/readme|\.md|docs\//.test(lowerFiles)) return 'docs';
  if (/test|spec/.test(lowerFiles)) return 'test';
  return 'feature';
}

function detectIssues(files, evidenceSnippets) {
  const lower = evidenceSnippets.join(' ').toLowerCase();
  const issues = [];
  if (lower.includes('todo') || lower.includes('fixme')) {
    issues.push('Diff contains TODO/FIXME markers that may indicate unfinished work.');
  }
  if (lower.includes('except:') || lower.includes('except exception')) {
    issues.push('Broad exception handling detected; consider narrowing exception types.');
  }
  const hasCode = files.some((p) => /\.(py|js|ts|tsx|jsx|go|java|cs|rb)$/i.test(p));
  const hasTest = files.some((p) => /test|spec/i.test(p));
  if (hasCode && !hasTest) {
    issues.push('Code changes detected without corresponding test file updates.');
  }
  if (lower.includes('password') || lower.includes('token')) {
    issues.push('Sensitive credential handling appears in diff; verify secure storage and masking.');
  }
  return issues;
}

function plannerDecision(review) {
  const issues = review.potential_issues || [];
  const risk = review.risk || 'low';
  const changeType = review.change_type || 'feature';

  let action = 'no_action';
  let reason = 'Diff appears low-risk and does not show clear issues requiring tracking.';

  if (issues.length > 0) {
    action = 'create_issue';
    reason = 'Potential quality/safety gaps were found in diff evidence.';
  } else if ((risk === 'high' || risk === 'medium') && ['feature', 'bugfix', 'refactor'].includes(changeType)) {
    action = 'create_pr';
    reason = 'Meaningful change with non-trivial risk should be tracked with PR context and test plan.';
  }

  return {
    action,
    reason,
    evidence_used: (review.evidence || []).slice(0, 3)
  };
}

function reflectionCheck(kind, draft, review) {
  const findings = [];
  const title = String(draft.title || '').trim();
  const body = String(draft.body || '').trim();

  if (!title) findings.push('Missing title.');
  if (!body) findings.push('Missing body.');
  if (!/evidence/i.test(body)) findings.push('Missing evidence section.');
  if ((kind === 'pr') && !/test plan/i.test(body)) findings.push('Missing test plan section.');
  if (!/risk level/i.test(body)) findings.push('Missing risk level section.');

  if (review && (!review.evidence || review.evidence.length === 0)) {
    findings.push('Review context has no supporting diff evidence.');
  }

  return {
    verdict: findings.length === 0 ? 'PASS' : 'FAIL',
    checks: {
      unsupported_claims: review ? 'PASS' : 'UNKNOWN',
      missing_evidence: /evidence/i.test(body) ? 'PASS' : 'FAIL',
      missing_tests: kind === 'issue' || /test plan/i.test(body) ? 'PASS' : 'FAIL',
      policy_violations: 'PASS'
    },
    findings
  };
}

function buildIssueDraft({ instruction, review }) {
  let title = 'Issue: follow-up improvements from repository review';
  let problem = 'Potential reliability and maintainability concerns were detected in recent changes.';
  let risk = 'medium';
  const evidenceItems = [];

  if (review) {
    risk = review.risk || 'medium';
    for (const item of (review.evidence || []).slice(0, 5)) {
      evidenceItems.push(`- ${item.source}: ${item.snippet}`);
    }
    if ((review.potential_issues || []).length) {
      problem = review.potential_issues.map((x) => `- ${x}`).join('\n');
    }
  }

  if (instruction) {
    const firstLine = instruction.split(/\r?\n/)[0].trim();
    if (firstLine) title = firstLine.slice(0, 120);
    problem = instruction;
  }

  const evidenceBlock = evidenceItems.length ? evidenceItems.join('\n') : '- Review evidence will be attached during implementation.';
  const body = `## Problem Description\n${problem}\n\n## Evidence\n${evidenceBlock}\n\n## Acceptance Criteria\n- Root cause is addressed with a minimal and testable change.\n- Regression risk is covered by tests or documented manual checks.\n- Any security or validation gaps are explicitly handled.\n\n## Risk Level\n- ${risk}`;

  return { title, body };
}

function buildPrDraft({ instruction, review, baseBranch, headBranch }) {
  let title = 'PR: repository improvements from agent review';
  let summary = 'Implements targeted improvements based on repository analysis.';
  let risk = 'medium';
  let files = [];

  if (review) {
    risk = review.risk || 'medium';
    files = review.files || [];
    const stats = review.stats || {};
    summary = `Change type: ${review.change_type}. Diff stats: +${stats.total_added || 0} /-${stats.total_deleted || 0}.`;
  }

  if (instruction) {
    const firstLine = instruction.split(/\r?\n/)[0].trim();
    if (firstLine) title = firstLine.slice(0, 120);
    summary = instruction;
  }

  const filesList = files.slice(0, 15).map((p) => `- ${p}`).join('\n') || '- To be confirmed';
  const body = `## Summary\n${summary}\n\n## Files Affected\n${filesList}\n\n## Evidence\n- Based on diff-derived review context and risk analysis.\n\n## Behavior Change\n- Improves repository quality and/or maintainability with scoped updates.\n\n## Test Plan\n- Run unit/integration tests covering touched modules.\n- Execute manual sanity check for the main user flow.\n\n## Risk Level\n- ${risk}`;

  return {
    title,
    body,
    head: headBranch,
    base: baseBranch
  };
}

function ensureStore() {
  const store = $getWorkflowStaticData('global');
  if (!store.reviews) store.reviews = {};
  if (!store.drafts) store.drafts = {};
  if (!store.outcomes) store.outcomes = {};
  return store;
}

async function githubRequest({ method = 'GET', path, body }) {
  requireGithubConfig();
  const response = await fetch(`${env.apiBase}/repos/${env.owner}/${env.repo}${path}`, {
    method,
    headers: {
      'Authorization': `Bearer ${env.token}`,
      'Accept': 'application/vnd.github+json',
      'X-GitHub-Api-Version': '2022-11-28',
      'Content-Type': 'application/json'
    },
    body: body ? JSON.stringify(body) : undefined
  });

  let data;
  try {
    data = await response.json();
  } catch (_err) {
    data = { message: await response.text() };
  }

  if (!response.ok) {
    const msg = data && data.message ? data.message : `GitHub API error (${response.status})`;
    throw new Error(msg);
  }
  return data;
}

async function handleReview() {
  const store = ensureStore();

  const commitRange = String(payload.commit_range || '').trim();
  const baseBranch = String(payload.base_branch || env.defaultBaseBranch).trim();
  const headBranch = String(payload.head_branch || env.defaultHeadBranch).trim();

  let compareRef = '';
  if (commitRange.includes('...')) {
    compareRef = commitRange;
  } else if (commitRange.includes('..')) {
    compareRef = commitRange.replace('..', '...');
  } else if (baseBranch && headBranch) {
    compareRef = `${baseBranch}...${headBranch}`;
  } else {
    throw new Error('For review, provide commit_range (base...head) or both base_branch and head_branch.');
  }

  const compare = await githubRequest({ method: 'GET', path: `/compare/${compareRef}` });
  const files = (compare.files || []).map((f) => f.filename);

  const evidence = [];
  for (const file of (compare.files || []).slice(0, 8)) {
    const patch = String(file.patch || '').split('\n');
    for (const line of patch) {
      if (line.startsWith('+') && !line.startsWith('+++')) {
        const snippet = line.slice(1).trim();
        if (snippet) evidence.push({ source: file.filename, type: 'added', snippet: snippet.slice(0, 200) });
      } else if (line.startsWith('-') && !line.startsWith('---')) {
        const snippet = line.slice(1).trim();
        if (snippet) evidence.push({ source: file.filename, type: 'removed', snippet: snippet.slice(0, 200) });
      }
      if (evidence.length >= 8) break;
    }
    if (evidence.length >= 8) break;
  }

  const totalAdded = (compare.files || []).reduce((acc, f) => acc + Number(f.additions || 0), 0);
  const totalDeleted = (compare.files || []).reduce((acc, f) => acc + Number(f.deletions || 0), 0);

  const evidenceSnippets = evidence.map((e) => e.snippet);
  const review = {
    input: {
      base_branch: baseBranch || null,
      head_branch: headBranch || null,
      commit_range: commitRange || null
    },
    reference: compareRef,
    change_type: classifyChange(files, evidenceSnippets),
    risk: assessRisk(files, totalAdded, totalDeleted),
    stats: {
      files_changed: files.length,
      total_added: totalAdded,
      total_deleted: totalDeleted
    },
    files,
    numstat: (compare.files || []).map((f) => ({
      path: f.filename,
      added: Number(f.additions || 0),
      deleted: Number(f.deletions || 0)
    })),
    potential_issues: detectIssues(files, evidenceSnippets),
    evidence
  };

  const plan = plannerDecision(review);
  const reviewId = makeId('rvw');
  store.reviews[reviewId] = { review, plan };

  return { ok: true, review_id: reviewId, review, plan };
}

async function handleDraft() {
  const store = ensureStore();

  const kind = String(payload.kind || 'issue').toLowerCase();
  const source = String(payload.source || 'instruction').toLowerCase();
  const instruction = String(payload.instruction || '').trim();
  const reviewId = payload.review_id ? String(payload.review_id) : '';

  let review = null;
  if (source === 'review') {
    if (!reviewId) throw new Error('review_id is required when source=review');
    const rec = store.reviews[reviewId];
    if (!rec) throw new Error('review_id not found');
    review = rec.review;
  }

  let draft;
  if (kind === 'issue') {
    draft = buildIssueDraft({ instruction, review });
  } else if (kind === 'pr') {
    const baseBranch = String(payload.base_branch || env.defaultBaseBranch || 'main');
    const headBranch = String(payload.head_branch || env.defaultHeadBranch || 'main');
    draft = buildPrDraft({ instruction, review, baseBranch, headBranch });
  } else {
    throw new Error('kind must be issue or pr');
  }

  const reflection = reflectionCheck(kind, draft, review);
  const draftId = makeId('drf');

  store.drafts[draftId] = {
    kind,
    source,
    instruction,
    review_id: reviewId || null,
    draft,
    reflection,
    status: 'pending_approval'
  };

  return {
    ok: true,
    draft_id: draftId,
    approval_required: true,
    draft,
    reflection
  };
}

async function handleApprove() {
  const store = ensureStore();

  const draftId = String(payload.draft_id || '').trim();
  const approve = Boolean(payload.approve);

  if (!draftId) throw new Error('draft_id is required');
  const record = store.drafts[draftId];
  if (!record) throw new Error('draft_id not found');

  if (!approve) {
    record.status = 'rejected';
    return { ok: true, message: 'Draft rejected. No changes made.' };
  }

  if ((record.reflection || {}).verdict !== 'PASS') {
    return {
      ok: false,
      message: 'Reflection verdict: FAIL. Revision required before creation.',
      reflection: record.reflection
    };
  }

  if (record.kind === 'issue') {
    const created = await githubRequest({
      method: 'POST',
      path: '/issues',
      body: { title: record.draft.title, body: record.draft.body }
    });

    const out = { kind: 'issue', number: created.number, url: created.html_url };
    record.status = 'created';
    record.created = out;
    store.outcomes[draftId] = out;
    return { ok: true, message: 'Created successfully.', created: out };
  }

  if (record.kind === 'pr') {
    const created = await githubRequest({
      method: 'POST',
      path: '/pulls',
      body: {
        title: record.draft.title,
        body: record.draft.body,
        head: record.draft.head,
        base: record.draft.base,
        draft: true
      }
    });

    const out = { kind: 'pr', number: created.number, url: created.html_url };
    record.status = 'created';
    record.created = out;
    store.outcomes[draftId] = out;
    return { ok: true, message: 'Created successfully.', created: out };
  }

  throw new Error(`Unsupported draft kind: ${record.kind}`);
}

async function handleImprove() {
  const kind = String(payload.kind || 'issue').toLowerCase();
  const number = Number(payload.number || 0);
  if (!number || number <= 0) throw new Error('number must be > 0');

  let current;
  if (kind === 'issue') {
    current = await githubRequest({ method: 'GET', path: `/issues/${number}` });
  } else if (kind === 'pr') {
    current = await githubRequest({ method: 'GET', path: `/pulls/${number}` });
  } else {
    throw new Error('kind must be issue or pr');
  }

  const source = {
    title: String(current.title || ''),
    body: String(current.body || '')
  };

  const findings = [];
  if (source.title.trim().length < 8) findings.push('Title is too short to communicate scope clearly.');
  if (!/acceptance criteria/i.test(source.body)) findings.push('Acceptance criteria are missing or not explicit.');
  if (!/evidence/i.test(source.body)) findings.push('Evidence section is missing.');
  if (!/risk/i.test(source.body)) findings.push('Risk level is missing.');
  if (findings.length === 0) findings.push('No major clarity gaps detected.');

  const criteriaLabel = kind === 'pr' ? 'Test Plan' : 'Acceptance Criteria';
  const suggestedBody = `## Problem / Summary\n${source.body.slice(0, 800) || 'Clarify the objective and expected outcome.'}\n\n## Evidence\n- Link concrete logs, diff snippets, or behavior examples.\n\n## ${criteriaLabel}\n- Define measurable completion conditions.\n- Add clear validation steps.\n\n## Risk Level\n- medium`;

  return {
    ok: true,
    critique: {
      kind,
      number,
      findings,
      source
    },
    suggested: {
      title: source.title || `${kind.toUpperCase()} #${number}: improved title`,
      body: suggestedBody,
      critique: findings.map((f) => `- ${f}`).join('\n')
    },
    reflection: {
      verdict: 'PASS',
      checks: {
        unsupported_claims: 'PASS',
        missing_evidence: 'PASS',
        missing_tests: kind === 'issue' ? 'PASS' : 'UNKNOWN',
        policy_violations: 'PASS'
      },
      findings: []
    }
  };
}

try {
  if (!action) {
    throw new Error('Missing action. Use one of: review, draft, approve, improve.');
  }

  let result;
  if (action === 'review') {
    result = await handleReview();
  } else if (action === 'draft') {
    result = await handleDraft();
  } else if (action === 'approve') {
    result = await handleApprove();
  } else if (action === 'improve') {
    result = await handleImprove();
  } else {
    throw new Error('Unsupported action. Use: review, draft, approve, improve.');
  }

  return [{ json: result }];
} catch (err) {
  return [{
    json: {
      ok: false,
      error: String((err && err.message) || err || 'Unknown error')
    }
  }];
}
